#include "primer/hyperloglog.h"

#include <algorithm>
#include <cmath>

namespace bustub {

template <typename KeyType>
HyperLogLog<KeyType>::HyperLogLog(int16_t n_bits) : cardinality_(0), n_bits_(n_bits) {
  // Initialize registers with 2^n_bits buckets
  if (n_bits > 0) {
    uint64_t num_buckets = 1ULL << n_bits;
    registers_.resize(num_buckets, 0);
  }
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeBinary(const hash_t &hash) const -> std::bitset<BITSET_CAPACITY> {
  // Convert the hash to a bitset
  return std::bitset<BITSET_CAPACITY>(hash);
}

template <typename KeyType>
auto HyperLogLog<KeyType>::PositionOfLeftmostOne(const std::bitset<BITSET_CAPACITY> &bset) const -> uint64_t {
  // Find the position of the leftmost 1-bit
  // If no 1-bit is found, return BITSET_CAPACITY
  for (uint64_t i = BITSET_CAPACITY; i > 0; --i) {
    if (bset[i - 1]) {
      return i;
    }
  }
  return 0;  // No 1-bit found
}

template <typename KeyType>
auto HyperLogLog<KeyType>::AddElem(KeyType val) -> void {
  if (n_bits_ <= 0) {
    return;  // Invalid configuration
  }

  // Hash the element
  hash_t hash = CalculateHash(val);

  // Get the bucket index from the first n_bits of the hash
  uint64_t bucket_idx = hash & ((1ULL << n_bits_) - 1);

  // Compute the remaining bits for finding the position of leftmost one
  hash_t remaining_hash = hash >> n_bits_;

  // Convert to bitset and find position of leftmost one
  std::bitset<BITSET_CAPACITY> binary = ComputeBinary(remaining_hash);
  uint64_t position = PositionOfLeftmostOne(binary);

  // Update the register if the new value is larger
  {
    std::lock_guard<std::mutex> lock(mutex_);
    if (position > registers_[bucket_idx]) {
      registers_[bucket_idx] = position;
    }
  }
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeCardinality() -> void {
  if (n_bits_ <= 0) {
    cardinality_ = 0;
    return;
  }

  std::lock_guard<std::mutex> lock(mutex_);

  uint64_t num_buckets = 1ULL << n_bits_;

  // Compute the harmonic mean of 2^(-M[j]) for all registers
  double sum = 0.0;
  for (uint64_t i = 0; i < num_buckets; ++i) {
    sum += std::pow(2.0, -static_cast<double>(registers_[i]));
  }

  // Apply the HyperLogLog formula
  double raw_estimate = CONSTANT * num_buckets * num_buckets / sum;

  // Apply small range and large range corrections
  // For standard HLL, we'll apply the straightforward formula
  cardinality_ = static_cast<size_t>(raw_estimate);
}

template class HyperLogLog<int64_t>;
template class HyperLogLog<std::string>;

}  // namespace bustub

